"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[83177],{31018:(t,e,l)=>{l.r(e),l.d(e,{data:()=>d});const d={key:"v-45aa7ad6",path:"/sqlserver/%E6%97%A5%E6%9C%9F.html",title:"",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"日期",slug:"日期",children:[{level:3,title:"一.数据类型",slug:"一-数据类型",children:[]},{level:3,title:"二.函数",slug:"二-函数",children:[]}]}],git:{updatedTime:1653451151e3,contributors:[{name:"panzhiyue",email:"30484534+panzhiyue@users.noreply.github.com",commits:1}]},filePathRelative:"sqlserver/日期.md"}},22055:(t,e,l)=>{l.r(e),l.d(e,{default:()=>s});const d=(0,l(57293).uE)('<p>[TOC]</p><h2 id="日期" tabindex="-1"><a class="header-anchor" href="#日期" aria-hidden="true">#</a> 日期</h2><h3 id="一-数据类型" tabindex="-1"><a class="header-anchor" href="#一-数据类型" aria-hidden="true">#</a> 一.数据类型</h3><h4 id="_1-date-格式-yyyy-mm-dd" tabindex="-1"><a class="header-anchor" href="#_1-date-格式-yyyy-mm-dd" aria-hidden="true">#</a> 1.DATE - 格式 YYYY-MM-DD</h4><h4 id="_2-datetime-格式-yyyy-mm-dd-hh-mm-ss" tabindex="-1"><a class="header-anchor" href="#_2-datetime-格式-yyyy-mm-dd-hh-mm-ss" aria-hidden="true">#</a> 2.DATETIME - 格式: YYYY-MM-DD HH:MM:SS</h4><h4 id="_3-smalldatetime-格式-yyyy-mm-dd-hh-mm-ss" tabindex="-1"><a class="header-anchor" href="#_3-smalldatetime-格式-yyyy-mm-dd-hh-mm-ss" aria-hidden="true">#</a> 3.SMALLDATETIME - 格式: YYYY-MM-DD HH:MM:SS</h4><h4 id="_4-timestamp-格式-唯一的数字" tabindex="-1"><a class="header-anchor" href="#_4-timestamp-格式-唯一的数字" aria-hidden="true">#</a> 4.TIMESTAMP - 格式: 唯一的数字</h4><h3 id="二-函数" tabindex="-1"><a class="header-anchor" href="#二-函数" aria-hidden="true">#</a> 二.函数</h3><h4 id="_1-getdate-返回当前日期和时间" tabindex="-1"><a class="header-anchor" href="#_1-getdate-返回当前日期和时间" aria-hidden="true">#</a> 1.GETDATE() 返回当前日期和时间</h4><p><strong>语法</strong></p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>GETDATE()\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>示例1 获取当前时间</strong></p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>SELECT GETDATE() AS CurrentDateTime\n--结果:2008-12-29 16:25:46.635\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>示例2 设置列默认值为当前时间</strong></p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>CREATE TABLE Orders \n(\nOrderId int NOT NULL PRIMARY KEY,\nProductName varchar(50) NOT NULL,\nOrderDate datetime NOT NULL DEFAULT GETDATE()\n)\n\nINSERT INTO Orders (ProductName) VALUES (&#39;Computer&#39;)\n\n--结果:1\t&#39;Computer&#39;\t2008-12-29 16:25:46.635\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_2-daterapt-返回日期-时间的单独部分-比如年、月、日、小时、分钟等等。" tabindex="-1"><a class="header-anchor" href="#_2-daterapt-返回日期-时间的单独部分-比如年、月、日、小时、分钟等等。" aria-hidden="true">#</a> 2.DATERAPT() 返回日期/时间的单独部分 ，比如年、月、日、小时、分钟等等。</h4><p><strong>语法</strong></p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>DATEPART(datepart,date)\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>参数说明</strong></p><ul><li><em>date</em> 参数是合法的日期表达式</li><li><em>datepart</em> 参数可以是下列的值：</li></ul><table><thead><tr><th style="text-align:left;">datepart</th><th style="text-align:left;">缩写</th></tr></thead><tbody><tr><td style="text-align:left;">年</td><td style="text-align:left;">yy, yyyy</td></tr><tr><td style="text-align:left;">季度</td><td style="text-align:left;">qq, q</td></tr><tr><td style="text-align:left;">月</td><td style="text-align:left;">mm, m</td></tr><tr><td style="text-align:left;">年中的日</td><td style="text-align:left;">dy, y</td></tr><tr><td style="text-align:left;">日</td><td style="text-align:left;">dd, d</td></tr><tr><td style="text-align:left;">周</td><td style="text-align:left;">wk, ww</td></tr><tr><td style="text-align:left;">星期</td><td style="text-align:left;">dw, w</td></tr><tr><td style="text-align:left;">小时</td><td style="text-align:left;">hh</td></tr><tr><td style="text-align:left;">分钟</td><td style="text-align:left;">mi, n</td></tr><tr><td style="text-align:left;">秒</td><td style="text-align:left;">ss, s</td></tr><tr><td style="text-align:left;">毫秒</td><td style="text-align:left;">ms</td></tr><tr><td style="text-align:left;">微妙</td><td style="text-align:left;">mcs</td></tr><tr><td style="text-align:left;">纳秒</td><td style="text-align:left;">ns</td></tr></tbody></table><p><strong>示例</strong></p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>SELECT DATEPART(yyyy,GETDATE()),DATEPART(mm,GETDATE())\n--结果:2021\t1\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_3-dateadd-在日期中添加或减去指定的时间间隔" tabindex="-1"><a class="header-anchor" href="#_3-dateadd-在日期中添加或减去指定的时间间隔" aria-hidden="true">#</a> 3.DATEADD() 在日期中添加或减去指定的时间间隔</h4><p><strong>语法</strong></p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>DATEADD(datepart,number,date)\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>参数说明</strong></p><ul><li><em>date</em> 参数是合法的日期表达式</li><li><em>number</em> 是您希望添加的间隔数 , 对于未来的时间，此数是正数，对于过去的时间，此数是负数。</li><li><em>datepart</em> 参数可以是下列的值：</li></ul><table><thead><tr><th style="text-align:left;">datepart</th><th style="text-align:left;">缩写</th></tr></thead><tbody><tr><td style="text-align:left;">年</td><td style="text-align:left;">yy, yyyy</td></tr><tr><td style="text-align:left;">季度</td><td style="text-align:left;">qq, q</td></tr><tr><td style="text-align:left;">月</td><td style="text-align:left;">mm, m</td></tr><tr><td style="text-align:left;">年中的日</td><td style="text-align:left;">dy, y</td></tr><tr><td style="text-align:left;">日</td><td style="text-align:left;">dd, d</td></tr><tr><td style="text-align:left;">周</td><td style="text-align:left;">wk, ww</td></tr><tr><td style="text-align:left;">星期</td><td style="text-align:left;">dw, w</td></tr><tr><td style="text-align:left;">小时</td><td style="text-align:left;">hh</td></tr><tr><td style="text-align:left;">分钟</td><td style="text-align:left;">mi, n</td></tr><tr><td style="text-align:left;">秒</td><td style="text-align:left;">ss, s</td></tr><tr><td style="text-align:left;">毫秒</td><td style="text-align:left;">ms</td></tr><tr><td style="text-align:left;">微妙</td><td style="text-align:left;">mcs</td></tr><tr><td style="text-align:left;">纳秒</td><td style="text-align:left;">ns</td></tr></tbody></table><p><strong>示例</strong></p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>SELECT GETDATE(),DATEADD(day,2,GETDATE()),DATEADD(yyyy,2,GETDATE())\n--结果:2021-01-05 18:43:13.620\t2021-01-07 18:43:13.620\t2023-01-05 18:43:13.620\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_4-datediff-返回两个日期之间的时间" tabindex="-1"><a class="header-anchor" href="#_4-datediff-返回两个日期之间的时间" aria-hidden="true">#</a> 4.DATEDIFF() 返回两个日期之间的时间</h4><p><strong>语法</strong></p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>DATEDIFF(datepart,startdate,enddate)\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>参数说明</strong></p><ul><li><p><em>startdate</em> 参数是合法的日期表达式。</p></li><li><p><em>enddate</em> 参数是合法的日期表达式。</p></li><li><p><em>datepart</em> 参数可以是下列的值：</p></li></ul><table><thead><tr><th style="text-align:left;">datepart</th><th style="text-align:left;">缩写</th></tr></thead><tbody><tr><td style="text-align:left;">年</td><td style="text-align:left;">yy, yyyy</td></tr><tr><td style="text-align:left;">季度</td><td style="text-align:left;">qq, q</td></tr><tr><td style="text-align:left;">月</td><td style="text-align:left;">mm, m</td></tr><tr><td style="text-align:left;">年中的日</td><td style="text-align:left;">dy, y</td></tr><tr><td style="text-align:left;">日</td><td style="text-align:left;">dd, d</td></tr><tr><td style="text-align:left;">周</td><td style="text-align:left;">wk, ww</td></tr><tr><td style="text-align:left;">星期</td><td style="text-align:left;">dw, w</td></tr><tr><td style="text-align:left;">小时</td><td style="text-align:left;">hh</td></tr><tr><td style="text-align:left;">分钟</td><td style="text-align:left;">mi, n</td></tr><tr><td style="text-align:left;">秒</td><td style="text-align:left;">ss, s</td></tr><tr><td style="text-align:left;">毫秒</td><td style="text-align:left;">ms</td></tr><tr><td style="text-align:left;">微妙</td><td style="text-align:left;">mcs</td></tr><tr><td style="text-align:left;">纳秒</td><td style="text-align:left;">ns</td></tr></tbody></table><p><strong>示例</strong></p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>SELECT DATEDIFF(day,&#39;2008-12-29&#39;,&#39;2008-11-30&#39;),DATEDIFF(mm,&#39;2008-12-29&#39;,&#39;2008-12-30&#39;)\n--结果:-29\t0\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_5-convert-用不同的格式显示日期-时间" tabindex="-1"><a class="header-anchor" href="#_5-convert-用不同的格式显示日期-时间" aria-hidden="true">#</a> 5.CONVERT() 用不同的格式显示日期/时间</h4><p><strong>语法</strong></p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>CONVERT(data_type(length),data_to_be_converted,style)\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>参数说明</strong></p><ul><li><em>data_type(length)</em> 规定目标数据类型（带有可选的长度）。</li><li><em>data_to_be_converted</em> 含有需要转换的值。</li><li><em>style</em> 规定日期/时间的输出格式。</li></ul><table><thead><tr><th style="text-align:left;">Style ID</th><th style="text-align:left;">Style 格式</th></tr></thead><tbody><tr><td style="text-align:left;">100 或者 0</td><td style="text-align:left;">mon dd yyyy hh:miAM （或者 PM）</td></tr><tr><td style="text-align:left;">101</td><td style="text-align:left;">mm/dd/yy</td></tr><tr><td style="text-align:left;">102</td><td style="text-align:left;">yy.mm.dd</td></tr><tr><td style="text-align:left;">103</td><td style="text-align:left;">dd/mm/yy</td></tr><tr><td style="text-align:left;">104</td><td style="text-align:left;">dd.mm.yy</td></tr><tr><td style="text-align:left;">105</td><td style="text-align:left;">dd-mm-yy</td></tr><tr><td style="text-align:left;">106</td><td style="text-align:left;">dd mon yy</td></tr><tr><td style="text-align:left;">107</td><td style="text-align:left;">Mon dd, yy</td></tr><tr><td style="text-align:left;">108</td><td style="text-align:left;">hh:mm:ss</td></tr><tr><td style="text-align:left;">109 或者 9</td><td style="text-align:left;">mon dd yyyy hh:mi:ss:mmmAM（或者 PM）</td></tr><tr><td style="text-align:left;">110</td><td style="text-align:left;">mm-dd-yy</td></tr><tr><td style="text-align:left;">111</td><td style="text-align:left;">yy/mm/dd</td></tr><tr><td style="text-align:left;">112</td><td style="text-align:left;">yymmdd</td></tr><tr><td style="text-align:left;">113 或者 13</td><td style="text-align:left;">dd mon yyyy hh:mm:ss:mmm(24h)</td></tr><tr><td style="text-align:left;">114</td><td style="text-align:left;">hh:mi:ss:mmm(24h)</td></tr><tr><td style="text-align:left;">120 或者 20</td><td style="text-align:left;">yyyy-mm-dd hh:mi:ss(24h)</td></tr><tr><td style="text-align:left;">121 或者 21</td><td style="text-align:left;">yyyy-mm-dd hh:mi:ss.mmm(24h)</td></tr><tr><td style="text-align:left;">126</td><td style="text-align:left;">yyyy-mm-ddThh:mm:ss.mmm（没有空格）</td></tr><tr><td style="text-align:left;">130</td><td style="text-align:left;">dd mon yyyy hh:mi:ss:mmmAM</td></tr><tr><td style="text-align:left;">131</td><td style="text-align:left;">dd/mm/yy hh:mi:ss:mmmAM</td></tr></tbody></table><p><strong>示例</strong></p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>select CONVERT(VARCHAR(19),GETDATE());\nselect CONVERT(VARCHAR(10),GETDATE(),110) ;\nselect CONVERT(VARCHAR(11),GETDATE(),106);\nselect CONVERT(VARCHAR(24),GETDATE(),113);\n\n--结果:\n01  5 2021  6:48PM\n01-05-2021\n05 01 2021\n05 01 2021 18:48:26:463\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>',47),a={},s=(0,l(63243).Z)(a,[["render",function(t,e){return d}]])},63243:(t,e)=>{e.Z=(t,e)=>{const l=t.__vccOpts||t;for(const[t,d]of e)l[t]=d;return l}}}]);